const seen = new Set();
const items = $input.all();

// Core blocklist keywords
const spamKeywords = [
  'promo', 'coupon', 'discount', 'deal', 'sale', 'save $', 
  '% off', 'price drop', 'sponsored', 'giveaway', 'bundle'
];

const uniqueAndClean = items.filter(i => {
  const url = i.json.link || i.json.url || '';
  const title = (i.json.title || '').toLowerCase();
  const snippet = (i.json.contentSnippet || '').toLowerCase();

  // 1. Skip if we've already seen this URL
  if (seen.has(url)) return false;

  // 2. Skip if title or snippet contains any spam keyword
  const isSpam = spamKeywords.some(keyword => title.includes(keyword) || snippet.includes(keyword));
  if (isSpam) return false;

  seen.add(url);
  return true;
});

// Sort by date (newest first)
uniqueAndClean.sort((a,b) => new Date(b.json.pubDate||0) - new Date(a.json.pubDate||0));

// Return top 10 clean items
return uniqueAndClean.slice(0,10).map(i => ({ 
  json: { 
    ...i.json, 
    _category: 'tech', 
    _chatId: $('Telegram Trigger').first().json.callback_query.message.chat.id 
  } 
}));

const items = $input.all();
const originalItems = $('Deduplicate Tech').all();
const chatId = $('Telegram Trigger').first()?.json?.callback_query?.message?.chat?.id
             || $('Deduplicate Tech').first()?.json?._chatId;

return items.map((item, i) => {
  const orig = originalItems[i]?.json || {};

  // Comprehensive RSS image extraction (multiple field formats)
  const imageUrl =
    orig.enclosure?.url ||
    orig['media:content']?.['$']?.url ||
    orig['media:content']?.url ||
    orig['media:thumbnail']?.['$']?.url ||
    orig['media:thumbnail']?.url ||
    orig.image?.url ||
    orig.image?.link ||
    (Array.isArray(orig['media:content'])
      ? orig['media:content'][0]?.['$']?.url
      : null) ||
    null;

  return {
    json: {
      ...orig,
      summary: item.json.text || item.json.output || item.json.response || '',
      imageUrl: imageUrl || null,
      _category: 'tech',
      _chatId: chatId || orig._chatId,
    },
  };
});

