// OG Image Scraper — Microlink-free, no spread, no Proxy risk
const item = $input.item;

// Pull only primitives we need — NO spread operator
const link     = String(item.json.link    || item.json.url || '');
const title    = String(item.json.title   || '');
const summary  = String(item.json.summary || item.json.contentSnippet || '');
const category = String(item.json._category || 'tech');

// chatId: try item first, fall back to Telegram Trigger
const chatId =
  item.json._chatId ||
  $('Telegram Trigger').first()?.json?.callback_query?.message?.chat?.id ||
  null;

// imageUrl from RSS (Parse Groq should already set this)
let imageUrl = item.json.imageUrl ? String(item.json.imageUrl) : null;

// HTML escape — Telegram HTML mode
function esc(s) {
  return String(s || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// Scrape OG image only when RSS gave us nothing
if (!imageUrl && link) {
  try {
    const res = await fetch(link, {
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; TelegramDigestBot/1.0)',
        'Accept': 'text/html,application/xhtml+xml;q=0.9,*/*;q=0.8',
      },
      redirect: 'follow',
      signal: AbortSignal.timeout(8000),
    });

    if (res.ok) {
      const html = await res.text();

      // og:image (both attribute orders)
      imageUrl =
        html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["'](https?:[^"'>\s]+)["']/i)?.[1] ||
        html.match(/<meta[^>]+content=["'](https?:[^"'>\s]+)["'][^>]+property=["']og:image["']/i)?.[1] ||
        html.match(/<meta[^>]+name=["']twitter:image["'][^>]+content=["'](https?:[^"'>\s]+)["']/i)?.[1] ||
        html.match(/<meta[^>]+content=["'](https?:[^"'>\s]+)["'][^>]+name=["']twitter:image["']/i)?.[1] ||
        html.match(/<meta[^>]+property=["']og:image:secure_url["'][^>]+content=["'](https?:[^"'>\s]+)["']/i)?.[1] ||
        null;

      if (imageUrl) imageUrl = imageUrl.trim();
    }
  } catch (_) {
    imageUrl = null;
  }
}

// Must be absolute http(s)
if (imageUrl && !/^https?:\/\//i.test(imageUrl)) imageUrl = null;

const safeTitle = esc(title);
const safeSummary = (() => {
  const s = esc(summary || 'No summary available.');
  return s.length > 750 ? s.slice(0, 747) + '...' : s;
})();

// Return 100% fresh plain object — no spread, no Proxy, no nested 'json' keys
return {
  json: {
    title,
    link,
    summary,
    _chatId: chatId,
    _category: category,
    imageUrl: imageUrl,
    _hasImage: imageUrl !== null,
    _safeTitle: safeTitle,
    _safeSummary: safeSummary,
    _safeLink: link,
  }
};

